sp_css.css:
/*
Collection of CSS that is used in multiple widgets
2.7.2 | 2021-12-27 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis
*/
.TaskerOverallStyleSheet {display: none;}

.dtech-box {
  display: flex;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-push-right {
  margin-left: auto!important;
}

.dtech-margin-top-4px {
  margin-top: 4px;
}

.dtech-margin-top-5px {
  margin-top: 5px;
}

.dtech-max-width-fit-content {
  max-width: fit-content;
}

.dtech-pad-all-10 {
  padding: 10px;
}

.dtech-push-right-flexbox {
  margin-left: auto;
}

.dtech-text-center {
  text-align: center;
}
